class Playground {
    async run(inputs) {
        const numsInput = inputs[0];
        const nums = numsInput.split(',').map(n => parseInt(n.trim())).filter(n => !isNaN(n));

        this.nums.init(nums);
        this.seen.init([]);
        this.log('Starting Contains Duplicate check...');
        await this.await();

        for (let i = 0; i < nums.length; i++) {
            const num = nums[i];

            this.nums.highlight(i, '#f59e0b');
            this.ptr.set('i', i);
            this.log(`Checking number: ${num}`);
            await this.await();

            this.log(`Is ` + num + ` in seen set?`);
            if (this.seen.has(num)) {
                this.log(`Yes! ` + num + ` is already seen.`);
                this.seen.highlight(num, '#10b981');
                this.log('Duplicate found! Returning true.');
                await this.await();
                return true;
            } else {
                this.log(`No. Adding ` + num + ` to seen set.`);
                this.seen.add(num);
                await this.await();
            }

             this.nums.highlight(i, '');
        }

        this.log('Finished. No duplicates found.');
        return false;
    }
}
